// minimal-working.js
import { ethers } from "ethers";

async function main() {
    console.log("🚀 MINIMAL WORKING CONTRACT\n");

    const provider = new ethers.JsonRpcProvider("http://127.0.0.1:7545");
    const signer = await provider.getSigner(0);
    console.log(`Account: ${await signer.getAddress()}\n`);

    // SIMPLEST POSSIBLE CONTRACT - just store and retrieve strings
    const bytecode = "";
    
    const abi = [
        "function add(string memory _item) public",
        "function get(uint256 _index) public view returns (string memory)",
        "function count() public view returns (uint256)"
    ];
    
    console.log("Deploying...");
    const factory = new ethers.ContractFactory(abi, bytecode, signer);
    const contract = await factory.deploy();
    await contract.waitForDeployment();
    const address = await contract.getAddress();
    console.log(`✅ Contract: ${address}\n`);
    
    console.log("Adding records...");
    await contract.add("Record 1: Test Data");
    console.log("   ✅ Added 1");
    
    await contract.add("Record 2: More Data");
    console.log("   ✅ Added 2");
    
    const total = await contract.count();
    console.log(`\n📊 Total records: ${total}`);
    
    console.log("\n🎉 WORKING!");
}

main().catch(console.error);
